parameters.jsCode:
// Parse the AI JSON output into slides array
const output = $input.first().json.output || '';

let slides = [];
try {
  const cleaned = output
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  const match = cleaned.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    slides = JSON.parse(match[0]);
  } else {
    slides = JSON.parse(cleaned);
  }
} catch (e) {
  throw new Error('Could not parse slide JSON from AI output. Output was: ' + output.substring(0, 300));
}

if (!Array.isArray(slides) || slides.length === 0) {
  throw new Error('No slides returned from AI. Check the prompt.');
}

const topic = $('1. Form — Carousel Topic + Details').item.json['Carousel Topic'];
const brandName = $('1. Form — Carousel Topic + Details').item.json['Your Name or Brand'];
const targetAudience = $('1. Form — Carousel Topic + Details').item.json['Target Audience'];
const tone = $('1. Form — Carousel Topic + Details').item.json['Tone'];

return [{
  json: {
    slides,
    slideCount: slides.length,
    topic,
    brandName,
    targetAudience,
    tone
  }
}];

// =============================================
// BRAND SETTINGS — CUSTOMIZE THESE
// =============================================
const BRAND_NAME = $('1. Form — Carousel Topic + Details').item.json['Your Name or Brand'] || 'YOUR_BRAND_NAME';
const BRAND_COLOR = '#0A66C2'; // LinkedIn blue — change to your brand color
const ACCENT_COLOR = '#ffffff';
const BG_COLOR = '#ffffff';
const TEXT_COLOR = '#1a1a1a';
const SLIDE_SIZE = '1080px';
const FONT = 'Arial, sans-serif';
// =============================================

const slides = $json.slides;
const topic = $json.topic;

let slidesHtml = '';

for (const slide of slides) {
  const isTitle = slide.type === 'title';
  const isCta = slide.type === 'cta';

  const slideBadge = (!isTitle && !isCta)
    ? `<div style="position:absolute;top:32px;right:32px;background:rgba(255,255,255,0.2);color:${ACCENT_COLOR};border-radius:50%;width:44px;height:44px;display:flex;align-items:center;justify-content:center;font-size:16px;font-weight:700;">${slide.slide_number}</div>`
    : '';

  let pointsHtml = '';
  if (slide.points && slide.points.length > 0) {
    pointsHtml = `
      <ul style="list-style:none;padding:0;margin:20px 0 0;">
        ${slide.points.map(point => `
          <li style="display:flex;align-items:flex-start;margin-bottom:18px;">
            <span style="min-width:28px;height:28px;background:rgba(255,255,255,0.25);border-radius:50%;display:flex;align-items:center;justify-content:center;margin-right:14px;margin-top:2px;font-size:13px;font-weight:700;color:${ACCENT_COLOR};">✓</span>
            <span style="font-size:20px;line-height:1.5;color:${ACCENT_COLOR};font-weight:400;">${point}</span>
          </li>`).join('')}
      </ul>`;
  }

  const subtitleHtml = slide.subtitle
    ? `<p style="font-size:${isTitle ? '22px' : '18px'};color:rgba(255,255,255,0.8);margin:12px 0 0;font-weight:300;line-height:1.4;">${slide.subtitle}</p>`
    : '';

  const swipePrompt = isTitle
    ? `<div style="position:absolute;bottom:32px;right:32px;background:rgba(255,255,255,0.2);border-radius:24px;padding:10px 20px;">
         <span style="color:${ACCENT_COLOR};font-size:15px;font-weight:500;">Swipe → </span>
       </div>`
    : '';

  const brandTag = `<div style="position:absolute;bottom:${isTitle ? '32px' : '28px'};left:32px;">
    <span style="color:rgba(255,255,255,0.7);font-size:14px;font-weight:500;">${BRAND_NAME}</span>
  </div>`;

  slidesHtml += `
    <div style="width:${SLIDE_SIZE};height:${SLIDE_SIZE};background:linear-gradient(135deg, ${BRAND_COLOR} 0%, #083f7a 100%);position:relative;display:flex;flex-direction:column;justify-content:center;padding:56px;box-sizing:border-box;page-break-after:always;overflow:hidden;">
      <div style="position:absolute;top:-80px;right:-80px;width:300px;height:300px;border-radius:50%;background:rgba(255,255,255,0.05);"></div>
      <div style="position:absolute;bottom:-60px;left:-60px;width:220px;height:220px;border-radius:50%;background:rgba(255,255,255,0.04);"></div>
      ${slideBadge}
      ${brandTag}
      ${swipePrompt}
      <div style="position:relative;z-index:2;">
        <div style="font-size:${isTitle ? '72px' : '56px'};margin-bottom:16px;">${slide.emoji}</div>
        <h1 style="font-size:${isTitle ? '48px' : '36px'};font-weight:800;color:${ACCENT_COLOR};margin:0;line-height:1.2;">${slide.headline}</h1>
        ${subtitleHtml}
        ${pointsHtml}
      </div>
    </div>`;
}

const fullHtml = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: ${FONT}; background: #000; }
    @page { size: ${SLIDE_SIZE} ${SLIDE_SIZE}; margin: 0; }
  </style>
</head>
<body>
${slidesHtml}
</body>
</html>`;

const cleanTopic = topic
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, '')
  .replace(/\s+/g, '-')
  .substring(0, 50);

const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const fileName = `linkedin-carousel-${cleanTopic}-${dateStr}.pdf`;

return [{
  json: {
    fullHtml,
    fileName,
    slideCount: slides.length,
    topic: $json.topic,
    brandName: $json.brandName,
    dateStr
  }
}];

// Generate PDF from HTML using html-pdf-node
// Make sure html-pdf-node is installed: npm install html-pdf-node

const htmlPdf = require('html-pdf-node');

const htmlContent = $json.fullHtml;
const fileName = $json.fileName;
const slideCount = $json.slideCount;
const slideSize = 1080;

const options = {
  format: 'A4',
  width: `${slideSize}px`,
  height: `${slideSize}px`,
  printBackground: true,
  margin: { top: '0px', right: '0px', bottom: '0px', left: '0px' },
  pageRanges: `1-${slideCount}`
};

const file = { content: htmlContent };

try {
  const pdfBuffer = await htmlPdf.generatePdf(file, options);
  const pdfBase64 = pdfBuffer.toString('base64');

  return [{
    json: {
      fileName: $json.fileName,
      slideCount: $json.slideCount,
      topic: $json.topic,
      brandName: $json.brandName,
      dateStr: $json.dateStr,
      pdfSize: pdfBuffer.length,
      mimeType: 'application/pdf'
    },
    binary: {
      data: {
        data: pdfBase64,
        mimeType: 'application/pdf',
        fileName: $json.fileName,
        fileExtension: 'pdf'
      }
    }
  }];
} catch (error) {
  throw new Error(`PDF generation failed: ${error.message}. Make sure html-pdf-node is installed on your n8n server.`);
}
